uint32_t ngap_generate_gNB_id(void)
{
  /* Retrieve the host name */
  char hostname[32] = {0};
  int const ret = gethostname(hostname, sizeof(hostname));
  DevAssert(ret == 0);
  uint8_t key[32] = {"eurecom"};
  byte_array_t data = {.len = 32, .buf = (uint8_t *)hostname};
  uint8_t out[32] = {0};
  kdf(key, data, 32, out);
  uint32_t const gNB_id = ((out[0] << 24) | (out[1] << 16) | (out[2] << 8) | out[3]);
  return gNB_id;
}

nssai_t decode_ngap_nssai(const NGAP_S_NSSAI_t *in)
{
  nssai_t nssai = {0};
  OCTET_STRING_TO_INT8(&in->sST, nssai.sst);
  if (in->sD != NULL) {
    BUFFER_TO_INT24(in->sD->buf, nssai.sd);
  } else {
    nssai.sd = 0xffffff;
  }
  return nssai;
}

int ngap_gNB_encode_pdu(NGAP_NGAP_PDU_t *pdu, uint8_t **buffer, uint32_t *len)
{
  int ret = -1;
  DevAssert(pdu != NULL);
  DevAssert(buffer != NULL);
  DevAssert(len != NULL);
  if (asn1_xer_print) {
    xer_fprint(stdout, &asn_DEF_NGAP_NGAP_PDU, (void *)pdu);
  }
  switch (pdu->present) {
    case NGAP_NGAP_PDU_PR_initiatingMessage:
      ret = ngap_gNB_encode_initiating(pdu, buffer, len);
      break;
    case NGAP_NGAP_PDU_PR_successfulOutcome:
      ret = ngap_gNB_encode_successfull_outcome(pdu, buffer, len);
      break;
    case NGAP_NGAP_PDU_PR_unsuccessfulOutcome:
      ret = ngap_gNB_encode_unsuccessfull_outcome(pdu, buffer, len);
      break;
    default:
      NGAP_DEBUG("Unknown message outcome (%d) or not implemented", (int)pdu->present);
      return -1;
  }
  ASN_STRUCT_FREE_CONTENTS_ONLY(asn_DEF_NGAP_NGAP_PDU, pdu);
  return ret;
}

ngap_ambr_t decode_ngap_UEAggregateMaximumBitRate(const NGAP_UEAggregateMaximumBitRate_t *in)
{
  ngap_ambr_t ambr = {0};
  asn_INTEGER2ulong(&in->uEAggregateMaximumBitRateUL, &ambr.br_ul);
  asn_INTEGER2ulong(&in->uEAggregateMaximumBitRateDL, &ambr.br_dl);
  return ambr;
}

